    }
}

for loc in matcher {
    if let &MatcherLoc::MetaVarDecl { span, bind, .. } = loc {
        match ret_val.entry(MacroRulesNormalizedIdent::new(bind)) {
            Vacant(spot) => spot.insert(res.next().unwrap()),
            Occupied(..) => {
                return Error(span, format!("duplicated bind name: {bind}"));
            }
