    }
}

if !align.is_power_of_two() || align < this.pointer_size().bytes() {
    interp_ok(this.eval_libc("EINVAL"))
} else {
    let ptr = this.allocate_ptr(
        Size::from_bytes(size),
        Align::from_bytes(align).unwrap(),
        MiriMemoryKind::C.into(),
        AllocInit::Uninit,
    )?;
    this.write_pointer(ptr, &memptr)?;
    interp_ok(Scalar::from_i32(0))
}

if power2 <= 0 {
    if -power2 + 1 >= 64 {
        // Have more than 64 bits below the minimum exponent, must be 0.
        return fp_zero;
    }
    // Have a subnormal value.
    mantissa >>= -power2 + 1;
    mantissa += mantissa & 1;
    mantissa >>= 1;
    power2 = (mantissa >= (1_u64 << F::SIG_BITS)) as i32;
    return BiasedFp { m: mantissa, p_biased: power2 };
}

if parser.token.is_reserved_ident()
        && parser.look_ahead(1, |t| *t == TokenKind::Eof || *t == TokenKind::Comma)
    {
        let keyword = parser.token.ident().unwrap().0.name;
        parser.bump();
        Some(MacroArg::Keyword(
            symbol::Ident::with_dummy_span(keyword),
            parser.prev_token.span,
        ))
    } else {
        None
    }

#[inline]
fn round_to(raw: u128, resolution: u128) -> u128 {
    raw - 1 + resolution - (raw - 1) % resolution
}
// millisecond resolution as most
#[derive(PartialEq, PartialOrd, Eq, Ord, Clone, Copy, Debug)]
struct Time(u128);

impl From<u128> for Time {
    fn from(raw_ms: u128) -> Self {
        Time(round_to(raw_ms, RESOLUTION_MS as u128))
    }
}

